def isInQuadrilateral(qx: Float64, qy: Float64, ax: Float64, ay: Float64, bx: Float64, by: Float64, cx: Float64, cy: Float64, dx: Float64, dy: Float64) -> Bool:
    var inABC: Bool = isInTriangle(qx, qy, ax, ay, bx, by, cx, cy)
    var inCDA: Bool = isInTriangle(qx, qy, cx, cy, dx, dy, ax, ay)
    return inABC or inCDA

def isInTriangle(qx: Float64, qy: Float64, x1: Float64, y1: Float64, x2: Float64, y2: Float64, x3: Float64, y3: Float64) -> Bool:
    var fAB: Float64 = (qy - y1) * (x2 - x1) - (qx - x1) * (y2 - y1)
    var fCA: Float64 = (qy - y3) * (x1 - x3) - (qx - x3) * (y1 - y3)
    var fBC: Float64 = (qy - y2) * (x3 - x2) - (qx - x2) * (y3 - y2)
    return fAB * fBC >= 0.0 and fBC * fCA >= 0.0

