def validMonthDay(month: Int, day: Int, leapYearAdd: Int) -> Bool:
    if month == 1 or month == 3 or month == 5 or month == 7 or month == 8 or month == 10 or month == 12:
        if day > 31:
            return False
    elif month == 4 or month == 6 or month == 9 or month == 11:
        if day > 30:
            return False
    elif month == 2:
        if day > 28 + leapYearAdd:
            return False
    else:
        return False
    return True
